CREATE OR REPLACE FUNCTION public.calc_uh_score(p_firma_id uuid, p_firma_turu_name text, p_moq integer, p_aylik_uretim_kapasitesi integer, p_fiziksel_magaza_sayisi integer, p_uretim_vardiyasi_id uuid, p_bagimsiz_denetim_id uuid, p_hizli_numune_id uuid, p_aylik_tedarik_sayisi integer, p_aylik_tedarik_birim_id uuid) RETURNS integer LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $uh_fn$
SELECT CASE
  WHEN p_firma_turu_name = 'Hazır Giyim Üreticisi' THEN ROUND(((CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000002') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000003') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000004') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000005') THEN 1 ELSE 0 END + CASE WHEN p_moq IS NOT NULL AND p_moq != 0 THEN 1 ELSE 0 END + CASE WHEN p_aylik_uretim_kapasitesi IS NOT NULL AND p_aylik_uretim_kapasitesi != 0 THEN 1 ELSE 0 END)::numeric / 6.0) * 6.0)::int
  WHEN p_firma_turu_name = 'Marka' THEN ROUND(((CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000002') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000004') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000003') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000019') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000020') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000021') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000022') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000099') THEN 1 ELSE 0 END + CASE WHEN p_fiziksel_magaza_sayisi IS NOT NULL AND p_fiziksel_magaza_sayisi != 0 THEN 1 ELSE 0 END)::numeric / 9.0) * 6.0)::int
  WHEN p_firma_turu_name = 'Mümessil Ofis' THEN ROUND(((CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000002') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000004') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000008') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000012') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000007') THEN 1 ELSE 0 END)::numeric / 5.0) * 6.0)::int
  WHEN p_firma_turu_name = 'Fason Atölye' THEN ROUND(((CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000002') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000004') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000003') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000007') THEN 1 ELSE 0 END + CASE WHEN p_uretim_vardiyasi_id IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN p_bagimsiz_denetim_id IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN p_hizli_numune_id IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN p_moq IS NOT NULL AND p_moq != 0 THEN 1 ELSE 0 END + CASE WHEN p_aylik_uretim_kapasitesi IS NOT NULL AND p_aylik_uretim_kapasitesi != 0 THEN 1 ELSE 0 END)::numeric / 9.0) * 6.0)::int
  WHEN p_firma_turu_name = 'Tedarikçi' THEN ROUND(((CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000013') THEN 1 ELSE 0 END + CASE WHEN EXISTS (SELECT 1 FROM firma_urun_hizmet_secimler s WHERE s.firma_id = p_firma_id AND s.kategori_id = 'a0000001-0000-0000-0000-000000000012') THEN 1 ELSE 0 END + CASE WHEN p_aylik_tedarik_sayisi IS NOT NULL AND p_aylik_tedarik_sayisi != 0 THEN 1 ELSE 0 END + CASE WHEN p_aylik_tedarik_birim_id IS NOT NULL THEN 1 ELSE 0 END)::numeric / 4.0) * 6.0)::int
  ELSE 0
END;
$uh_fn$;